          "excludeFromSubmit": true,
          "watchFields": [
            "qty",
            "price"
          ],
          "calculation": {
            "rule": "multiply"
          },
          "decimals": 2,
          "variant": "highlight"
        },
        {
          "type": "preview",
          "name": "orderLabel",
          "label": "Order Label",
          "excludeFromSubmit": true,
          "watchFields": [
            "product",
            "qty",
            "currency"
          ],
          "format": "{qty}x {product} ({currency})",
          "emptyText": "Fill in order details",
          "variant": "card",
          "colSpan": 2
